143 /// Return the source operand of a potentially bitcasted value. If there is no
144 /// bitcast, return the input value itself.
145 static Value *peekThroughBitcasts(Value *V) {
146   while (auto *BitCast = dyn_cast<BitCastInst>(V))
147     V = BitCast->getOperand(0);
148   return V;
149 }
