172 bool VectorCombine::vectorizeLoadInsert(Instruction &I) {
173   // Match insert into fixed vector of scalar value.
174   // TODO: Handle non-zero insert index.
175   Value *Scalar;
176   if (!match(&I, m_InsertElt(m_Undef(), m_Value(Scalar), m_ZeroInt())) ||
177       !Scalar->hasOneUse())
178     return false;
179 
180   // Optionally match an extract from another vector.
181   Value *X;
182   bool HasExtract = match(Scalar, m_ExtractElt(m_Value(X), m_ZeroInt()));
183   if (!HasExtract)
184     X = Scalar;
185 
186   auto *Load = dyn_cast<LoadInst>(X);
187   if (!canWidenLoad(Load, TTI))
188     return false;
189 
190   Type *ScalarTy = Scalar->getType();
191   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
192   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
193 
194   // Check safety of replacing the scalar load with a larger vector load.
195   // We use minimal alignment (maximum flexibility) because we only care about
196   // the dereferenceable region. When calculating cost and creating a new op,
197   // we may use a larger value based on alignment attributes.
198   Value *SrcPtr = Load->getPointerOperand()->stripPointerCasts();
199   assert(isa<PointerType>(SrcPtr->getType()) && "Expected a pointer type");
200 
201   unsigned MinVecNumElts = MinVectorSize / ScalarSize;
202   auto *MinVecTy = VectorType::get(ScalarTy, MinVecNumElts, false);
203   unsigned OffsetEltIndex = 0;
204   Align Alignment = Load->getAlign();
205   if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
206                                    &DT)) {
207     // It is not safe to load directly from the pointer, but we can still peek
208     // through gep offsets and check if it safe to load from a base address with
209     // updated alignment. If it is, we can shuffle the element(s) into place
210     // after loading.
211     unsigned OffsetBitWidth = DL->getIndexTypeSizeInBits(SrcPtr->getType());
212     APInt Offset(OffsetBitWidth, 0);
213     SrcPtr = SrcPtr->stripAndAccumulateInBoundsConstantOffsets(*DL, Offset);
214 
215     // We want to shuffle the result down from a high element of a vector, so
216     // the offset must be positive.
217     if (Offset.isNegative())
218       return false;
219 
220     // The offset must be a multiple of the scalar element to shuffle cleanly
221     // in the element's size.
222     uint64_t ScalarSizeInBytes = ScalarSize / 8;
223     if (Offset.urem(ScalarSizeInBytes) != 0)
224       return false;
225 
226     // If we load MinVecNumElts, will our target element still be loaded?
227     OffsetEltIndex = Offset.udiv(ScalarSizeInBytes).getZExtValue();
228     if (OffsetEltIndex >= MinVecNumElts)
229       return false;
230 
231     if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
232                                      &DT))
233       return false;
234 
235     // Update alignment with offset value. Note that the offset could be negated
236     // to more accurately represent "(new) SrcPtr - Offset = (old) SrcPtr", but
237     // negation does not change the result of the alignment calculation.
238     Alignment = commonAlignment(Alignment, Offset.getZExtValue());
239   }
240 
241   // Original pattern: insertelt undef, load [free casts of] PtrOp, 0
242   // Use the greater of the alignment on the load or its source pointer.
243   Alignment = std::max(SrcPtr->getPointerAlignment(*DL), Alignment);
244   Type *LoadTy = Load->getType();
245   unsigned AS = Load->getPointerAddressSpace();
246   InstructionCost OldCost =
247       TTI.getMemoryOpCost(Instruction::Load, LoadTy, Alignment, AS);
248   APInt DemandedElts = APInt::getOneBitSet(MinVecNumElts, 0);
249   TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
